import java.io.IOException;
import java.io.PrintWriter;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html>");
            out.println("<body>");

            // Encode user input before outputting it to prevent XSS
            Encoder encoder = ESAPI.encoder();
            out.println("<h1>Hello, " + encoder.encodeForHTML(userInput) + "</h1>");

            out.println("</body>");
            out.println("</html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
